// src/App.js

import React from "react";
import { BrowserRouter as Router, Routes, Route } from "react-router-dom";
import { AuthProvider } from "./context/AuthContext";
import LoginPage from "./pages/LoginPage";
import RegisterPage from "./pages/RegisterPage";
import StudentLanding from "./pages/StudentLanding";
import ProfessorLanding from "./pages/ProfessorLanding";
import SecretaryLanding from "./pages/SecretaryLanding";
import AdminLanding from "./pages/AdminLanding";

const App = () => {
  return (
    <AuthProvider>
      <Router>
        <Routes>
          <Route path="/" element={<LoginPage />} />
          <Route path="/register" element={<RegisterPage />} />
          <Route path="/student-landing" element={<StudentLanding />} />
          <Route path="/professor-landing" element={<ProfessorLanding />} />
          <Route path="/secretary-landing" element={<SecretaryLanding />} />
          <Route path="/admin-landing" element={<AdminLanding />} />
        </Routes>
      </Router>
    </AuthProvider>
  );
};

export default App;
